let ball;
let ground;
let t = 0;
let landed = false;

function setup() {
  canvas();
  enablePhysics({ gravity: { y: 1 } });

  ground = groundBody();
  ball = circleBody({ x: width / 2, y: 50, r: 12, restitution: 0.6 });
}

function draw() {
  background(240);

  if (ground) {
    fill('#8B7355');
    noStroke();
    let b = ground.body.bounds;
    rect(b.min.x, b.min.y, b.max.x - b.min.x, b.max.y - b.min.y);
  }

  if (ball) {
    fill('#FFD700');
    stroke('#B8860B');
    strokeWeight(2);
    circle(ball.body.position.x, ball.body.position.y, 24);

    if (!landed) {
      t += 1/60;
      updateRef('point_1', t, ball.y);

      if (ball.body.speed < 0.5 && ball.body.position.y >= ground.body.bounds.min.y - 13) {
        landed = true;
      }
    }
  }
}

let boxes = [];
let ground;

function setup() {
  canvas();
  enablePhysics({ gravity: { y: 1 } });
  ground = groundBody();

  for (let i = 0; i < 5; i++) {
    boxes.push(rectBody({
      x: 100 + i * 60,
      y: 50 + i * 30,
      w: 30, h: 30,
      restitution: 0.3,
      color: 'steelblue'
    }));
  }
}

function draw() {
  background(240);

  if (ground) {
    fill('#8B7355');
    noStroke();
    let b = ground.body.bounds;
    rect(b.min.x, b.min.y, b.max.x - b.min.x, b.max.y - b.min.y);
  }

  for (let box of boxes) {
    push();
    translate(box.body.position.x, box.body.position.y);
    rotate(box.body.angle);
    fill('steelblue');
    stroke('navy');
    strokeWeight(2);
    rectMode(CENTER);
    rect(0, 0, 30, 30);
    pop();
  }
}

let ball;
let ground;

function setup() {
  canvas();
  enablePhysics({ gravity: { y: 1 } });
  ground = groundBody();
  ball = circleBody({ x: width / 2, y: height / 2, r: 15, restitution: 0.7 });
}

function draw() {
  background(240);

  if (ground) {
    fill('#8B7355');
    noStroke();
    let b = ground.body.bounds;
    rect(b.min.x, b.min.y, b.max.x - b.min.x, b.max.y - b.min.y);
  }

  if (ball) {
    fill('#FF6347');
    stroke('#8B0000');
    strokeWeight(2);
    circle(ball.body.position.x, ball.body.position.y, 30);
  }
}

function mousePressed() {
  if (ball) {
    applyForce(ball, 0, -0.05);
  }
}
